//! grove — Phase 1: one engine, two faces.
//!
//! The same operations are exposed as a human CLI (`grove outline …`) and as an
//! MCP server (`grove serve`). Both call `ops`; neither owns engine logic.

mod engine;
mod fetch;
mod ingest;
mod init;
mod mcp;
mod ops;
mod registry;

use std::path::PathBuf;

use anyhow::Result;
use clap::{Parser, Subcommand};

#[derive(Parser)]
#[command(name = "grove", version, about = "Structural sight for coding agents (Phase 1)")]
struct Cli {
    /// Emit JSON instead of the human table.
    #[arg(long, global = true)]
    json: bool,
    #[command(subcommand)]
    cmd: Cmd,
}

#[derive(Subcommand)]
enum Cmd {
    /// List the definitions in one file (kind · name · parent · signature · id).
    Outline {
        file: PathBuf,
        /// Only this kind (e.g. class, function, method).
        #[arg(long)]
        kind: Option<String>,
        /// JSON detail: 0 terse · 1 default (no byte offsets) · 2 full.
        #[arg(long, default_value_t = 1)]
        detail: u8,
    },
    /// Find symbols across a directory, optionally filtered.
    Symbols {
        dir: PathBuf,
        /// Only this kind (e.g. function, struct, method).
        #[arg(long)]
        kind: Option<String>,
        /// Only definitions whose name equals this exactly (case-insensitive).
        #[arg(long)]
        name: Option<String>,
        /// Substring matching for --name (case-insensitive) instead of exact equality.
        #[arg(long = "name-contains", alias = "name-substr")]
        name_contains: bool,
        /// Include references, not just definitions.
        #[arg(long)]
        refs: bool,
    },
    /// Print the full source of a symbol, by id or by file + name.
    Source {
        /// A symbol id from outline/symbols, e.g. rust:src/lib.rs#parse@41
        id_or_file: String,
        /// If the first arg is a file, the symbol name to find in it.
        name: Option<String>,
    },
    /// Report ERROR / MISSING nodes — a post-edit syntax check.
    Check { file: PathBuf },
    /// Find references to a symbol across a directory (structural + textual).
    Callers {
        /// The symbol name to find references to.
        name: String,
        /// Directory to search.
        #[arg(short, long, default_value = ".")]
        dir: PathBuf,
    },
    /// Compact structural map: definitions and their references, no source bodies.
    Map {
        dir: PathBuf,
        /// Only definitions of this kind (e.g. function, class, method).
        #[arg(long)]
        kind: Option<String>,
        /// Only definitions whose name equals this exactly (case-insensitive).
        #[arg(long)]
        name: Option<String>,
        /// Substring matching for --name (case-insensitive) instead of exact equality.
        #[arg(long = "name-contains", alias = "name-substr")]
        name_contains: bool,
    },
    /// Find where a symbol is defined (go-to-def), by name or by position.
    ///
    /// `name` is an exact-name lookup (may return several candidates). `--at` is
    /// the precise mode: it resolves the identifier under a usage site,
    /// scope-aware (a local/parameter shadows a same-named global) and following
    /// imports across files, falling back to name lookup when it can't resolve.
    Definition {
        /// The symbol name to resolve (omit when using --at).
        name: Option<String>,
        /// Directory to search.
        #[arg(short, long, default_value = ".")]
        dir: PathBuf,
        /// Resolve the identifier at a usage site: file:line:col (1-based).
        /// Scope-aware + cross-file; prefer this when you have a position.
        #[arg(long)]
        at: Option<String>,
    },
    /// Set up grove in a project: fetch grammars + grove.lock, and wire up the
    /// chosen integration (MCP server, the cross-harness skill, or both).
    Init {
        /// Project directory (default: current).
        #[arg(default_value = ".")]
        path: PathBuf,
        /// Which integration to set up: mcp (default), skill, or both.
        #[arg(long = "as", value_enum, default_value_t = init::Target::Mcp)]
        target: init::Target,
        /// Show what would be detected/written without writing.
        #[arg(long)]
        dry_run: bool,
    },
    /// Download grammars from the hosted registry into the OS cache.
    Fetch {
        /// Languages to fetch (default: all in the catalog).
        langs: Vec<String>,
        /// Re-download even if already cached.
        #[arg(long)]
        force: bool,
    },
    /// Build registry artifacts from curated source specs (registry maintainer step).
    Ingest {
        /// Only these languages (default: all in the sources file).
        only: Vec<String>,
        /// Curated sources spec.
        #[arg(long, default_value = "registry-sources.json")]
        sources: PathBuf,
        /// Output registry directory.
        #[arg(long, default_value = "registry")]
        out: PathBuf,
    },
    /// Build the hosted catalog (index.json) for a registry directory.
    Index {
        /// Registry directory to index (default: the resolved registry root).
        dir: Option<PathBuf>,
        /// Output path (default: <dir>/index.json).
        #[arg(short, long)]
        output: Option<PathBuf>,
        /// Serve grammar.wasm as release assets from this base URL (GitHub Releases).
        #[arg(long)]
        release_base: Option<String>,
    },
    /// Show the resolved registry location and search order.
    Registry,
    /// List the languages available in the registry.
    Languages,
    /// Write grove.lock pinning each registry grammar's version + content hash.
    Lock,
    /// Run as an MCP server over stdio (the agent-facing face).
    Serve,
}

fn main() -> Result<()> {
    let cli = Cli::parse();
    match cli.cmd {
        Cmd::Outline { file, kind, detail } => {
            let syms = ops::outline(&file, kind.as_deref())?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&ops::project(&syms, detail))?);
            } else {
                for s in &syms {
                    let owner = s.parent.clone().unwrap_or_default();
                    println!("{:<10} {:<26} {:<18} {}:{:<4} {}", s.kind, s.name, owner, s.line, s.col, s.signature);
                }
                eprintln!("\n{} definitions · {}", syms.len(), ops::rel(&file));
            }
        }
        Cmd::Symbols { dir, kind, name, name_contains, refs } => {
            let syms = ops::symbols(&dir, kind.as_deref(), name.as_deref(), refs, name_contains)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&syms)?);
            } else {
                for s in &syms {
                    let mark = if s.is_definition { "def" } else { "ref" };
                    println!("{:<3} {:<10} {:<28} {}", mark, s.kind, s.name, s.id);
                }
                eprintln!("\n{} symbols", syms.len());
            }
        }
        Cmd::Source { id_or_file, name } => {
            let res = ops::source(&id_or_file, name.as_deref())?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&res)?);
            } else {
                if !res.other_candidates.is_empty() {
                    eprintln!("(also matched: {})", res.other_candidates.join(", "));
                }
                println!("{}", res.source);
            }
        }
        Cmd::Check { file } => {
            let defects = ops::check(&file)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&defects)?);
            } else if defects.is_empty() {
                println!("ok · no syntax errors · {}", ops::rel(&file));
            } else {
                for d in &defects {
                    println!("{:<8} {}:{:<4} `{}`", d.kind, d.line, d.col, d.text);
                }
                eprintln!("\n{} defect(s) · {}", defects.len(), ops::rel(&file));
                std::process::exit(1);
            }
        }
        Cmd::Callers { name, dir } => {
            let sites = ops::callers(&dir, &name)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&sites)?);
            } else {
                for s in &sites {
                    let inf = s.in_function.as_deref().unwrap_or("<top-level>");
                    // Lead with `path:line:col` so the location is greppable and,
                    // for a directory-wide query, you can tell which file it's in (#29).
                    // [S]/[T] = structural (tree-sitter) vs textual (grep) provenance (#33).
                    let tag = if s.source == "structural" { "S" } else { "T" };
                    println!("{}:{}:{}   {:<28} [{}] {}", s.file, s.line, s.col, inf, tag, s.text);
                }
                eprintln!("\n{} reference(s) of `{}` (S=structural, T=textual)", sites.len(), name);
            }
        }
        Cmd::Map { dir, kind, name, name_contains } => {
            let maps = ops::map(&dir, kind.as_deref(), name.as_deref(), name_contains)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&maps)?);
            } else {
                for fm in &maps {
                    println!("{}", fm.file);
                    for e in &fm.entries {
                        let parent = e.parent.as_deref().unwrap_or("");
                        if e.references.is_empty() {
                            println!("  {:<10} {:<26} {:<18} {:<4} {}", e.kind, e.name, parent, e.row, e.signature);
                        } else {
                            println!("  {:<10} {:<26} {:<18} {:<4} {}  → {}", e.kind, e.name, parent, e.row, e.signature, e.references.join(", "));
                        }
                    }
                }
                let total: usize = maps.iter().map(|fm| fm.entries.len()).sum();
                eprintln!("\n{} definitions across {} files", total, maps.len());
            }
        }
        Cmd::Definition { name, dir, at } => {
            let (resolved, defs) = match at {
                Some(pos) => {
                    let (file, row, col) = ops::parse_pos(&pos)?;
                    ops::definition_at(&file, row, col, &dir)?
                }
                None => {
                    let name = name.ok_or_else(|| anyhow::anyhow!("provide a name or --at"))?;
                    (name.clone(), ops::definition(&dir, &name)?)
                }
            };
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&defs)?);
            } else {
                for s in &defs {
                    let owner = s.parent.clone().unwrap_or_default();
                    // `definition` searches a whole dir, so results can span
                    // files — lead with `file:line:col` so the caller knows
                    // which file each hit is in without a follow-up `symbols`.
                    let loc = format!("{}:{}:{}", s.file, s.line, s.col);
                    println!("{:<10} {:<26} {:<18} {:<28} {}", s.kind, s.name, owner, loc, s.signature);
                }
                eprintln!("\n{} definition(s) of `{}`", defs.len(), resolved);
            }
        }
        Cmd::Init { path, target, dry_run } => init::run(&path, target, dry_run)?,
        Cmd::Fetch { langs, force } => fetch::run(&langs, force)?,
        Cmd::Ingest { only, sources, out } => ingest::run(&sources, &out, &only)?,
        Cmd::Index { dir, output, release_base } => {
            let (out, n) = registry::write_index(dir, output, release_base.as_deref())?;
            println!("wrote {} ({n} grammars)", out.display());
        }
        Cmd::Registry => {
            println!("registry root: {}\n", registry::root().display());
            println!("search order (first existing wins):");
            for c in registry::search_path() {
                let mark = if c.exists { "✓" } else { "·" };
                println!("  {mark} {:<26} {}", c.source, c.path.display());
            }
        }
        Cmd::Languages => {
            let manifests = registry::manifests();
            if cli.json {
                let v: Vec<_> = manifests
                    .iter()
                    .map(|m| serde_json::json!({"name": m.name, "version": m.version, "extensions": m.extensions}))
                    .collect();
                println!("{}", serde_json::to_string_pretty(&v)?);
            } else {
                for m in &manifests {
                    println!("{:<12} {:<10} .{}", m.name, m.version, m.extensions.join(" ."));
                }
                eprintln!("\n{} language(s) in registry", manifests.len());
            }
        }
        Cmd::Lock => {
            let lock = registry::write_lock(std::path::Path::new("grove.lock"))?;
            println!("wrote grove.lock ({} grammars)", lock);
        }
        Cmd::Serve => mcp::serve()?,
    }
    Ok(())
}

//! The structural engine: parse + tag extraction + syntax check, over grammars
//! loaded from the registry as wasm.
//!
//! Tags are extracted by running the grammar's `tags.scm` through the Query
//! engine (interpreting `@definition.*` / `@reference.*` / `@name` captures),
//! because `tree-sitter-tags` cannot drive a wasm-loaded language. The same path
//! serves every language, static or wasm.

use std::cell::RefCell;
use std::collections::HashMap;
use std::sync::OnceLock;

use anyhow::{anyhow, Context, Result};
use serde::Serialize;
use streaming_iterator::StreamingIterator;
use tree_sitter::{Language, Node, Parser, Query, QueryCursor, WasmStore};

use crate::registry::{Grammar, Profile};

/// A definition or reference extracted from a file.
#[derive(Debug, Serialize)]
pub struct Symbol {
    /// Stable handle: `<lang>:<relpath>#<name>@<line>` (line is 1-based). Survives across turns.
    pub id: String,
    pub name: String,
    /// e.g. `function`, `method`, `class`, `call` — from the grammar's tag query.
    pub kind: String,
    pub is_definition: bool,
    pub file: String,
    /// 1-based line and column of the name — the editor / `grep -n` convention,
    /// so a citation printed as "line N" lands on the right line. (tree-sitter's
    /// own `Point` is 0-based; we normalize here. The byte range below, not these,
    /// is what `source` slices.)
    pub line: usize,
    pub col: usize,
    /// Byte range of the whole symbol (what `source` slices).
    pub start_byte: usize,
    pub end_byte: usize,
    /// The trimmed source line containing the name — a compact signature.
    pub signature: String,
    /// The owning container — the `impl` type, trait, class, or module.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub parent: Option<String>,
}

/// A syntactic defect found by `check`.
#[derive(Debug, Serialize)]
pub struct Defect {
    pub kind: &'static str,
    /// 1-based line and column — same editor / `grep -n` convention as `Symbol`.
    pub line: usize,
    pub col: usize,
    pub start_byte: usize,
    pub end_byte: usize,
    pub text: String,
}

// The per-language node-kind profile is data now — it comes from the grammar's
// manifest (`registry::Profile`), not a table compiled in here.

// ---- loaded-grammar cache (load each wasm grammar once per process) ----

fn engine() -> &'static tree_sitter::wasmtime::Engine {
    static E: OnceLock<tree_sitter::wasmtime::Engine> = OnceLock::new();
    E.get_or_init(tree_sitter::wasmtime::Engine::default)
}

struct Loaded {
    parser: Parser,
    /// Held to anchor the wasm-loaded language's lifetime alongside its store.
    #[allow(dead_code)]
    language: Language,
    tags_query: Query,
    capture_names: Vec<String>,
    /// Compiled `locals.scm`, with its capture-name table. `None` when the
    /// grammar ships no locals query.
    locals: Option<CapturedQuery>,
    /// Compiled `imports.scm`, with its capture-name table. `None` when the
    /// grammar ships no imports query.
    imports: Option<CapturedQuery>,
}

/// A compiled query plus its capture-name lookup table.
struct CapturedQuery {
    query: Query,
    capture_names: Vec<String>,
}

impl CapturedQuery {
    fn compile(language: &Language, src: &str, what: &str) -> Result<CapturedQuery> {
        let query = Query::new(language, src).with_context(|| format!("compiling {what} query"))?;
        let capture_names = query.capture_names().iter().map(|s| s.to_string()).collect();
        Ok(CapturedQuery { query, capture_names })
    }

    /// Compile an *optional* query (`locals.scm` / `imports.scm`) without letting
    /// a bad one break the grammar. These come from the registry and may be
    /// authored upstream against a different grammar version; a query that fails
    /// to compile (e.g. references a node kind this grammar doesn't have) must
    /// degrade to "feature off", never poison the core tools. Returns `None` on
    /// absence or compile error, warning once on the latter.
    fn compile_optional(
        language: &Language,
        src: &Option<std::sync::Arc<String>>,
        what: &str,
    ) -> Option<CapturedQuery> {
        let src = src.as_ref()?;
        // Defense-in-depth: tree-sitter *supertype* patterns (`(super/sub)`) can
        // hard-crash the wasm query engine at *match* time — not catchable like a
        // compile error. Some upstream `locals.scm` use them. Refuse such a query
        // outright (feature off) rather than risk a segfault on a hosted file.
        if has_supertype_pattern(src) {
            eprintln!("grove: ignoring {what} query (unsupported supertype `(a/b)` syntax)");
            return None;
        }
        match CapturedQuery::compile(language, src, what) {
            Ok(q) => Some(q),
            Err(e) => {
                eprintln!("grove: ignoring invalid {what} query: {e:#}");
                None
            }
        }
    }
}

/// Detect tree-sitter supertype node syntax `(name/name` outside string literals.
/// Queries use `/` only for supertypes; predicate args containing `/` live inside
/// quotes, which we skip. Conservative — a false positive just disables an
/// optional feature, never breaks core tools.
fn has_supertype_pattern(src: &str) -> bool {
    let b = src.as_bytes();
    let mut in_str = false;
    let mut in_comment = false; // `;` to end-of-line — query comments often hold `/` ("if/else")
    let is_ident = |c: u8| c.is_ascii_alphanumeric() || c == b'_';
    for i in 0..b.len() {
        let c = b[i];
        if in_comment {
            if c == b'\n' {
                in_comment = false;
            }
            continue;
        }
        match c {
            b'"' if i == 0 || b[i - 1] != b'\\' => in_str = !in_str,
            b';' if !in_str => in_comment = true,
            b'/' if !in_str => {
                let prev = i.checked_sub(1).map(|j| b[j]).unwrap_or(0);
                let next = b.get(i + 1).copied().unwrap_or(0);
                if is_ident(prev) && is_ident(next) {
                    return true;
                }
            }
            _ => {}
        }
    }
    false
}

impl Loaded {
    fn load(g: &Grammar) -> Result<Loaded> {
        let mut store = WasmStore::new(engine()).map_err(|e| anyhow!("wasm store: {e:?}"))?;
        let language = store
            .load_language(&g.name, &g.wasm)
            .map_err(|e| anyhow!("loading `{}` grammar from wasm: {e:?}", g.name))?;
        let tags_query =
            Query::new(&language, &g.tags_query).context("compiling tags query")?;
        let capture_names = tags_query
            .capture_names()
            .iter()
            .map(|s| s.to_string())
            .collect();
        let locals = CapturedQuery::compile_optional(&language, &g.locals_query, "locals");
        let imports = CapturedQuery::compile_optional(&language, &g.imports_query, "imports");
        let mut parser = Parser::new();
        parser
            .set_wasm_store(store)
            .map_err(|e| anyhow!("attaching wasm store: {e}"))?;
        parser
            .set_language(&language)
            .map_err(|e| anyhow!("setting language: {e}"))?;
        Ok(Loaded { parser, language, tags_query, capture_names, locals, imports })
    }
}

thread_local! {
    static CACHE: RefCell<HashMap<String, Loaded>> = RefCell::new(HashMap::new());
}

fn with_loaded<R>(g: &Grammar, f: impl FnOnce(&mut Loaded) -> Result<R>) -> Result<R> {
    CACHE.with(|c| {
        let mut map = c.borrow_mut();
        if !map.contains_key(&g.name) {
            let loaded = Loaded::load(g)?;
            map.insert(g.name.clone(), loaded);
        }
        f(map.get_mut(&g.name).unwrap())
    })
}

// ---- extraction ----

/// Parse `source` with `parser` — the single choke point for parsing, so cost
/// (and, in tests, the parse count) lives in one place.
fn parse_source(parser: &mut Parser, source: &[u8]) -> Result<tree_sitter::Tree> {
    #[cfg(test)]
    parse_counter::bump();
    parser.parse(source, None).context("parse produced no tree")
}

/// Test-only parse counter, used to prove `callers` parses each file once.
/// Thread-local so it counts only the parses on the calling test's thread —
/// immune to other tests parsing in parallel.
#[cfg(test)]
pub mod parse_counter {
    use std::cell::Cell;
    thread_local! {
        static COUNT: Cell<usize> = const { Cell::new(0) };
    }
    pub(super) fn bump() {
        COUNT.with(|c| c.set(c.get() + 1));
    }
    pub fn reset() {
        COUNT.with(|c| c.set(0));
    }
    pub fn get() -> usize {
        COUNT.with(Cell::get)
    }
}

fn symbol_id(lang: &str, rel: &str, name: &str, line: usize) -> String {
    format!("{lang}:{rel}#{name}@{line}")
}

/// The trimmed source line containing `byte`.
fn line_text(source: &[u8], byte: usize) -> String {
    let start = source[..byte.min(source.len())]
        .iter()
        .rposition(|&b| b == b'\n')
        .map_or(0, |i| i + 1);
    let end = source[byte.min(source.len())..]
        .iter()
        .position(|&b| b == b'\n')
        .map_or(source.len(), |i| byte + i);
    String::from_utf8_lossy(&source[start..end]).trim().to_string()
}

/// Extract all tags (definitions + references) from one file's source.
pub fn extract(grammar: &Grammar, rel: &str, source: &[u8]) -> Result<Vec<Symbol>> {
    extract_with_tree(grammar, rel, source).map(|(syms, _)| syms)
}

/// Like [`extract`], but also returns the parsed tree so a caller that needs a
/// second pass (e.g. `callers`' enclosing-function lookup) can reuse it instead
/// of re-parsing the identical bytes. Parsing dominates tree-sitter cost.
pub fn extract_with_tree(
    grammar: &Grammar,
    rel: &str,
    source: &[u8],
) -> Result<(Vec<Symbol>, tree_sitter::Tree)> {
    with_loaded(grammar, |lg| {
        let tree = parse_source(&mut lg.parser, source)?;
        let mut cursor = QueryCursor::new();
        let mut matches = cursor.matches(&lg.tags_query, tree.root_node(), source);

        let mut out = Vec::new();
        while let Some(m) = matches.next() {
            let mut anchor: Option<(Node, String, bool)> = None;
            let mut name_node: Option<Node> = None;
            for cap in m.captures {
                let cn = &lg.capture_names[cap.index as usize];
                if let Some(kind) = cn.strip_prefix("definition.") {
                    anchor = Some((cap.node, kind.to_string(), true));
                } else if let Some(kind) = cn.strip_prefix("reference.") {
                    anchor = Some((cap.node, kind.to_string(), false));
                } else if cn == "name" {
                    name_node = Some(cap.node);
                }
            }
            let Some((node, kind, is_definition)) = anchor else {
                continue;
            };
            let nn = name_node.unwrap_or(node);
            let name = nn.utf8_text(source).unwrap_or("").to_string();
            if name.is_empty() {
                continue;
            }
            let pos = nn.start_position();
            // Some upstream tags queries anchor `@definition.function` on a
            // declarator (e.g. C's `function_declarator`) that spans only the
            // signature, not the body. Expand to the enclosing full-function
            // node so `source` returns the complete body. The name position and
            // signature line stay anchored on the name itself.
            let span = definition_span(node, &kind, &grammar.profile);
            // tree-sitter `Point` is 0-based; surface 1-based line/col so the
            // agent-facing handle and output read as human line numbers (#31).
            let line = pos.row + 1;
            out.push(Symbol {
                id: symbol_id(&grammar.name, rel, &name, line),
                name,
                kind,
                is_definition,
                file: rel.to_string(),
                line,
                col: pos.column + 1,
                start_byte: span.start_byte(),
                end_byte: span.end_byte(),
                signature: line_text(source, nn.start_byte()),
                parent: None,
            });
        }

        // Overlapping tag patterns can match the same node twice (e.g. a method
        // matches both @definition.function and @definition.method). Keep the
        // first match per (range, is_definition) — query order puts the more
        // specific pattern first.
        let mut seen = std::collections::HashSet::new();
        out.retain(|s| seen.insert((s.start_byte, s.end_byte, s.is_definition)));

        // Second pass: fill parents from the same tree. Search starts at the
        // def node's *parent* so a container (e.g. a class) is never its own parent.
        let root = tree.root_node();
        for s in &mut out {
            s.parent = root
                .descendant_for_byte_range(s.start_byte, s.end_byte)
                .and_then(|def| def.parent())
                .and_then(|p| nearest_container(p, source, &grammar.profile));
        }
        Ok((out, tree))
    })
}

/// The full source of a symbol, given its byte range.
pub fn slice<'a>(source: &'a [u8], sym: &Symbol) -> &'a str {
    std::str::from_utf8(&source[sym.start_byte..sym.end_byte]).unwrap_or("<non-utf8>")
}

/// Parse a file and report every ERROR / MISSING node.
pub fn check(grammar: &Grammar, source: &[u8]) -> Result<Vec<Defect>> {
    with_loaded(grammar, |lg| {
        let tree = parse_source(&mut lg.parser, source)?;
        let mut defects = Vec::new();
        collect_defects(tree.root_node(), source, &mut defects);
        Ok(defects)
    })
}

fn collect_defects(node: Node, source: &[u8], out: &mut Vec<Defect>) {
    if node.is_error() || node.is_missing() {
        let start = node.start_position();
        out.push(Defect {
            kind: if node.is_missing() { "missing" } else { "error" },
            line: start.row + 1,
            col: start.column + 1,
            start_byte: node.start_byte(),
            end_byte: node.end_byte(),
            text: String::from_utf8_lossy(&source[node.byte_range()])
                .chars()
                .take(60)
                .collect(),
        });
    }
    let mut cursor = node.walk();
    for child in node.children(&mut cursor) {
        collect_defects(child, source, out);
    }
}

/// The node whose byte range best represents the *whole* function definition.
///
/// Upstream tags queries vary in what they anchor `@definition.function` on:
/// Rust/Python capture the full function node (body included), but C's query
/// anchors on `function_declarator`, which spans only the signature. When the
/// captured node is such a declarator nested inside a full-function node (per
/// the profile's `function_kinds`), climb to that node so the symbol's byte
/// range covers the body. A bare prototype (no enclosing function node) keeps
/// the declarator range — it has no body to miss.
fn definition_span<'a>(node: Node<'a>, kind: &str, profile: &Profile) -> Node<'a> {
    if kind != "function" && kind != "method" {
        return node;
    }
    let is_fn_kind = |n: &Node| profile.function_kinds.iter().any(|k| k.as_str() == n.kind());
    if is_fn_kind(&node) {
        return node;
    }
    let mut cur = node.parent();
    while let Some(n) = cur {
        if is_fn_kind(&n) {
            return n;
        }
        cur = n.parent();
    }
    node
}

// ---- position resolution (parent / enclosing-fn / go-to-def) ----

/// Name of the nearest container (impl type / trait / class / module) at or
/// above `node`, per the language profile. Pass the def node's parent to exclude
/// the node itself.
fn nearest_container(node: Node, source: &[u8], profile: &Profile) -> Option<String> {
    let mut cur = Some(node);
    while let Some(n) = cur {
        for (kind, field) in &profile.containers {
            if kind.as_str() == n.kind() {
                if let Some(c) = n.child_by_field_name(field) {
                    let text = c.utf8_text(source).ok()?;
                    return Some(text.split('<').next().unwrap_or(text).trim().to_string());
                }
            }
        }
        cur = n.parent();
    }
    None
}

/// Run a closure with the parsed tree of `source` under `grammar`. The closure
/// receives the root node and the grammar's profile.
pub fn with_tree<R>(
    grammar: &Grammar,
    source: &[u8],
    f: impl FnOnce(Node, &Profile) -> R,
) -> Result<R> {
    with_loaded(grammar, |lg| {
        let tree = parse_source(&mut lg.parser, source)?;
        Ok(f(tree.root_node(), &grammar.profile))
    })
}

/// Name of a function node. Prefers a direct `name` field (Rust/Python/JS);
/// falls back to descending the `declarator` chain to the identifier (C, where
/// `function_definition` has no `name` field — the name sits under
/// `function_declarator`, possibly through `pointer_declarator`).
fn function_name(node: Node, source: &[u8], profile: &Profile) -> Option<String> {
    if let Some(n) = node.child_by_field_name("name") {
        return n.utf8_text(source).ok().map(str::to_string);
    }
    let mut cur = node.child_by_field_name("declarator")?;
    loop {
        if profile.identifier_kinds.iter().any(|k| k.as_str() == cur.kind()) {
            return cur.utf8_text(source).ok().map(str::to_string);
        }
        cur = cur.child_by_field_name("declarator")?;
    }
}

/// Name of the function/method enclosing `byte`, qualified by container.
pub fn enclosing_function_at(
    root: Node,
    byte: usize,
    source: &[u8],
    profile: &Profile,
) -> Option<String> {
    let mut node = root.descendant_for_byte_range(byte, byte)?;
    loop {
        if profile.function_kinds.iter().any(|k| k.as_str() == node.kind()) {
            let fname = function_name(node, source, profile)?;
            let container = node
                .parent()
                .and_then(|p| nearest_container(p, source, profile));
            return Some(match container {
                Some(c) => format!("{c}::{fname}"),
                None => fname,
            });
        }
        node = node.parent()?;
    }
}

/// The identifier text at a (row, col) position — for go-to-def.
pub fn identifier_at(
    root: Node,
    row: usize,
    col: usize,
    source: &[u8],
    profile: &Profile,
) -> Option<String> {
    let point = tree_sitter::Point { row, column: col };
    let node = root.descendant_for_point_range(point, point)?;
    if profile.identifier_kinds.iter().any(|k| k.as_str() == node.kind()) {
        node.utf8_text(source).ok().map(str::to_string)
    } else {
        None
    }
}

/// Build a `Symbol` for a locally-bound definition. The captured
/// `@local.definition` node is the binding identifier; line/col anchor on it,
/// while the byte span expands to its parent statement (the `let`, `parameter`,
/// or `assignment`) so `source` returns the whole binding, not a bare name.
fn local_symbol(grammar: &Grammar, rel: &str, name_node: Node, source: &[u8]) -> Symbol {
    let pos = name_node.start_position();
    let line = pos.row + 1;
    let name = name_node.utf8_text(source).unwrap_or("").to_string();
    let span = name_node.parent().unwrap_or(name_node);
    Symbol {
        id: symbol_id(&grammar.name, rel, &name, line),
        name,
        kind: "local".to_string(),
        is_definition: true,
        file: rel.to_string(),
        line,
        col: pos.column + 1,
        start_byte: span.start_byte(),
        end_byte: span.end_byte(),
        signature: line_text(source, name_node.start_byte()),
        parent: None,
    }
}

/// Scope-aware go-to-def: resolve the identifier at `(row, col)` to its nearest
/// enclosing **local** binding, using the grammar's `locals.scm`.
///
/// Returns `Ok(None)` when the grammar ships no locals query, the cursor is not
/// on an identifier, or the name has no enclosing local definition (a free /
/// global reference — the caller then falls back to directory-wide lookup).
/// Innermost enclosing scope wins, so shadowing resolves correctly. This is a
/// single-file, single-parse, stateless operation — no index.
pub fn resolve_local_at(
    grammar: &Grammar,
    rel: &str,
    source: &[u8],
    row: usize,
    col: usize,
) -> Result<Option<Symbol>> {
    with_loaded(grammar, |lg| {
        let Some(locals) = &lg.locals else {
            return Ok(None);
        };
        let tree = parse_source(&mut lg.parser, source)?;
        let root = tree.root_node();

        let point = tree_sitter::Point { row, column: col };
        let Some(ref_node) = root.descendant_for_point_range(point, point) else {
            return Ok(None);
        };
        if !grammar
            .profile
            .identifier_kinds
            .iter()
            .any(|k| k.as_str() == ref_node.kind())
        {
            return Ok(None);
        }
        let name = ref_node.utf8_text(source).unwrap_or("");
        if name.is_empty() {
            return Ok(None);
        }

        // Collect scope ranges and definition nodes from the locals query.
        let mut scopes: Vec<Node> = Vec::new();
        let mut defs: Vec<Node> = Vec::new();
        let mut cursor = QueryCursor::new();
        let mut matches = cursor.matches(&locals.query, root, source);
        while let Some(m) = matches.next() {
            for cap in m.captures {
                // Prefix-match so subtyped captures from upstream files work too
                // (e.g. julia's `@local.definition.function`, `@local.scope.*`).
                let cn = locals.capture_names[cap.index as usize].as_str();
                if cn.starts_with("local.scope") {
                    scopes.push(cap.node);
                } else if cn.starts_with("local.definition") {
                    defs.push(cap.node);
                }
            }
        }

        // Scopes enclosing the reference, innermost (smallest span) first.
        let (rs, re) = (ref_node.start_byte(), ref_node.end_byte());
        let mut enclosing: Vec<Node> = scopes
            .into_iter()
            .filter(|s| s.start_byte() <= rs && s.end_byte() >= re)
            .collect();
        enclosing.sort_by_key(|s| s.end_byte() - s.start_byte());

        for scope in &enclosing {
            let hit = defs.iter().find(|d| {
                d.start_byte() >= scope.start_byte()
                    && d.end_byte() <= scope.end_byte()
                    && d.utf8_text(source).map(|t| t == name).unwrap_or(false)
            });
            if let Some(d) = hit {
                return Ok(Some(local_symbol(grammar, rel, *d, source)));
            }
        }
        Ok(None)
    })
}

/// One name brought into a file by an import statement (ADR 0001 Step 2).
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ImportBinding {
    /// The name as referenced in *this* file — the alias when aliased, else the
    /// imported name. This is what a cursor on a use resolves against.
    pub name: String,
    /// The original name in the target module (what to look up there). Equals
    /// `name` when the import is not aliased.
    pub source: String,
    /// The module path text, verbatim from the import (e.g. `foo.bar`, `./util`).
    pub module: String,
}

/// Extract every import binding from a file, via the grammar's `imports.scm`
/// (`@import.name` / optional `@import.source` / `@import.module`). Returns an
/// empty vec when the grammar ships no imports query. Pure single-file parse.
pub fn extract_imports(grammar: &Grammar, source: &[u8]) -> Result<Vec<ImportBinding>> {
    with_loaded(grammar, |lg| {
        let Some(imports) = &lg.imports else {
            return Ok(Vec::new());
        };
        let tree = parse_source(&mut lg.parser, source)?;
        let mut out = Vec::new();
        let mut cursor = QueryCursor::new();
        let mut matches = cursor.matches(&imports.query, tree.root_node(), source);
        while let Some(m) = matches.next() {
            let (mut name, mut src, mut module) = (None, None, None);
            for cap in m.captures {
                let text = cap.node.utf8_text(source).unwrap_or("").to_string();
                match imports.capture_names[cap.index as usize].as_str() {
                    "import.name" => name = Some(text),
                    "import.source" => src = Some(text),
                    "import.module" => module = Some(text),
                    _ => {}
                }
            }
            // A binding needs at least a bound name and a module to resolve.
            if let (Some(name), Some(module)) = (name, module) {
                let source = src.unwrap_or_else(|| name.clone());
                out.push(ImportBinding { name, source, module });
            }
        }
        Ok(out)
    })
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::registry;

    fn rust() -> Grammar {
        registry::resolve("rust").expect("rust grammar (dev stub or cache)")
    }

    /// Regression guard for #31: the reported `line` must equal the real
    /// `grep -n` line of the definition (1-based), per grammar. The off-by-one
    /// clustered by language, so this asserts across every dev-stub grammar with
    /// the def deliberately placed below line 1 — where a 0-vs-1 slip would show.
    #[test]
    fn reported_line_matches_grep_n_per_grammar() {
        // (lang, source, def name). `target` sits on the 3rd line in each — the
        // line `grep -n target` would report.
        let cases: &[(&str, &str, &str)] = &[
            ("rust", "// header\n\nfn target() {}\n", "target"),
            ("python", "# header\n\ndef target():\n    pass\n", "target"),
            ("javascript", "// header\n\nfunction target() {}\n", "target"),
        ];
        for (lang, src, name) in cases {
            let Ok(g) = registry::resolve(lang) else {
                eprintln!("skipping {lang}: grammar not resolvable in this environment");
                continue;
            };
            let want_line = src
                .lines()
                .position(|l| l.contains(&format!(" {name}")) || l.contains(&format!("{name}(")))
                .map(|i| i + 1)
                .expect("fixture contains the def");
            let syms = extract(&g, &format!("demo.{lang}"), src.as_bytes()).unwrap();
            let def = syms
                .iter()
                .find(|s| s.name == *name && s.is_definition)
                .unwrap_or_else(|| panic!("{lang}: no def named {name}"));
            assert_eq!(
                def.line, want_line,
                "{lang}: reported line {} != grep -n line {want_line}",
                def.line
            );
            // The id's `@<line>` must carry the same 1-based line.
            assert!(
                def.id.ends_with(&format!("@{want_line}")),
                "{lang}: id {} should end with @{want_line}",
                def.id
            );
        }
    }

    #[test]
    fn check_passes_clean_source() {
        let defects = check(&rust(), b"fn main() {}\n").unwrap();
        assert!(defects.is_empty(), "valid rust has no defects, got {defects:?}");
    }

    #[test]
    fn check_reports_defects_on_broken_source() {
        // Unbalanced delimiters force ERROR / MISSING nodes.
        let defects = check(&rust(), b"fn main( {\n").unwrap();
        assert!(!defects.is_empty(), "broken rust must report a defect");
        assert!(defects.iter().all(|d| d.kind == "error" || d.kind == "missing"));
        assert!(defects.iter().all(|d| d.end_byte >= d.start_byte));
    }

    #[test]
    fn extract_finds_definitions_with_container_parent() {
        let src = b"struct S;\nimpl S {\n    fn method(&self) {}\n}\n";
        let syms = extract(&rust(), "lib.rs", src).unwrap();
        let m = syms
            .iter()
            .find(|s| s.name == "method" && s.is_definition)
            .expect("method definition");
        assert_eq!(m.parent.as_deref(), Some("S"), "method's container is impl S");
        assert!(m.id.starts_with("rust:lib.rs#method@"), "stable id, got {}", m.id);
    }

    #[test]
    fn rust_definition_span_covers_the_whole_body() {
        // Rust anchors @definition.function on the full function node, so the
        // captured range already spans the body. Guards against regressing the
        // common case while exercising the slice/range path.
        let src = b"fn f() {\n    let x = 1;\n    x + 1\n}\n";
        let syms = extract(&rust(), "lib.rs", src).unwrap();
        let f = syms.iter().find(|s| s.name == "f" && s.is_definition).unwrap();
        let body = slice(src, f);
        assert!(body.starts_with("fn f()"), "starts at signature: {body:?}");
        assert!(body.trim_end().ends_with('}'), "includes closing brace: {body:?}");
    }

    #[test]
    fn c_function_definition_span_includes_the_body() {
        // C's upstream tags query anchors @definition.function on
        // `function_declarator` (signature only). The engine must expand the
        // range to the enclosing `function_definition` so `source` returns the
        // full body. Skip where the C grammar isn't installed (the dev stub
        // ships rust/python/js only).
        let Ok(c) = registry::resolve("c") else {
            eprintln!("skipping: C grammar not resolvable in this environment");
            return;
        };
        let src = b"static int *get_thing(const char *s,\n                      int n)\n{\n\tint total = 0;\n\treturn &total;\n}\n";
        let syms = extract(&c, "demo.c", src).unwrap();
        let f = syms
            .iter()
            .find(|s| s.name == "get_thing" && s.is_definition)
            .expect("get_thing definition");
        let body = slice(src, f);
        assert!(body.contains("int total = 0"), "body included: {body:?}");
        assert!(body.contains("return &total"), "body included: {body:?}");
        assert!(body.trim_end().ends_with('}'), "closing brace included: {body:?}");
        // The pointer return type sits above the declarator — expansion must
        // reach the whole `function_definition`, not just the declarator.
        assert!(body.starts_with("static int *"), "return type included: {body:?}");
        // Name position still anchors on the identifier, not the expanded span.
        assert_eq!(f.line, 1, "name on the first line (1-based)");
    }

    #[test]
    fn c_callers_capture_calls_with_enclosing_function() {
        // Two-part regression for #27: C's curated tags must capture
        // `@reference.call`, and `enclosing_function_at` must resolve a C
        // function's name through the declarator chain (C `function_definition`
        // has no `name` field). Skip where the C grammar isn't installed.
        let Ok(c) = registry::resolve("c") else {
            eprintln!("skipping: C grammar not resolvable in this environment");
            return;
        };
        let src = b"static int helper(int x) { return x + 1; }\nstatic int caller_one(void) { return helper(5); }\n";
        let (syms, tree) = extract_with_tree(&c, "demo.c", src).unwrap();
        let call = syms
            .iter()
            .find(|s| s.name == "helper" && !s.is_definition)
            .expect("helper call captured as a reference");
        assert_eq!(call.kind, "call", "call reference kind");
        let enc = enclosing_function_at(tree.root_node(), call.start_byte, src, &c.profile);
        assert_eq!(enc.as_deref(), Some("caller_one"), "enclosing fn resolved for C");
    }

    #[test]
    fn extract_with_tree_returns_a_reusable_tree() {
        let src = b"fn helper() {}\nfn caller() {\n    helper();\n}\n";
        let (syms, tree) = extract_with_tree(&rust(), "lib.rs", src).unwrap();
        assert!(syms.iter().any(|s| s.name == "helper" && s.is_definition));
        // The returned tree is usable for the enclosing-function pass.
        let call = syms.iter().find(|s| s.name == "helper" && !s.is_definition).unwrap();
        let enc = enclosing_function_at(tree.root_node(), call.start_byte, src, &rust().profile);
        assert_eq!(enc.as_deref(), Some("caller"));
    }

    #[test]
    fn slice_returns_the_symbols_bytes() {
        let src = b"fn only() { let x = 1; }\n";
        let syms = extract(&rust(), "lib.rs", src).unwrap();
        let f = syms.iter().find(|s| s.name == "only").unwrap();
        let body = slice(src, f);
        assert!(body.starts_with("fn only"));
        assert!(body.contains("let x = 1"));
    }

    #[test]
    fn identifier_at_resolves_the_name_under_the_cursor() {
        let src = b"fn helper() {}\nfn caller() {\n    helper();\n}\n";
        let g = rust();
        let name = with_tree(&g, src, |root, profile| {
            // row 2 (0-based), col 4 — start of `helper` in the call.
            identifier_at(root, 2, 4, src, profile)
        })
        .unwrap();
        assert_eq!(name.as_deref(), Some("helper"));
    }

    #[test]
    fn enclosing_function_at_qualifies_method_with_its_type() {
        let src = b"struct S;\nimpl S {\n    fn m(&self) {\n        let _ = 1;\n    }\n}\n";
        let g = rust();
        // A byte inside the method body.
        let needle = src.windows(9).position(|w| w == b"let _ = 1").unwrap();
        let enc = with_tree(&g, src, |root, profile| {
            enclosing_function_at(root, needle, src, profile)
        })
        .unwrap();
        assert_eq!(enc.as_deref(), Some("S::m"), "method qualified by container type");
    }

    /// 0-based (row, col) of a byte offset — mirrors tree-sitter's `Point`.
    fn row_col(src: &str, byte: usize) -> (usize, usize) {
        let before = &src[..byte];
        let row = before.matches('\n').count();
        let col = byte - before.rfind('\n').map_or(0, |i| i + 1);
        (row, col)
    }

    /// The rust grammar *with* its `locals.scm`, or `None` when it resolved from a
    /// root that ships no locals query (e.g. a populated OS cache on a dev box).
    /// A clean checkout / CI resolves the dev tree `registry/`, which has it. The
    /// `GROVE_REGISTRY`-pinned integration suite (`tests/cli.rs`) covers this path
    /// unconditionally; these unit tests add white-box coverage when available.
    fn rust_with_locals() -> Option<Grammar> {
        let g = rust();
        if g.locals_query.is_none() {
            eprintln!("skipping: rust grammar resolved without locals.scm (non-dev-stub root)");
            return None;
        }
        Some(g)
    }

    #[test]
    fn resolve_local_prefers_the_shadowing_binding() {
        let Some(g) = rust_with_locals() else { return };
        // A local `run` shadows the module-level `fn run`. Go-to-def on the *use*
        // of `run` must land on the local binding (line 3), not the global (line 1).
        let src = "fn run() {}\nfn caller() {\n    let run = 1;\n    let _x = run;\n}\n";
        let use_byte = src.rfind("run").unwrap(); // the `run` in `let _x = run;`
        let (row, col) = row_col(src, use_byte);
        let got = resolve_local_at(&g, "demo.rs", src.as_bytes(), row, col)
            .unwrap()
            .expect("a local binding should resolve");
        assert_eq!(got.name, "run");
        assert_eq!(got.kind, "local");
        assert_eq!(got.line, 3, "must resolve to the local `let run`, not the global fn");
        assert!(got.id.ends_with("@3"), "id carries the local's line, got {}", got.id);
    }

    #[test]
    fn resolve_local_returns_none_for_a_global_reference() {
        let Some(g) = rust_with_locals() else { return };
        // `helper` has no local binding in scope — resolution must decline so the
        // caller falls back to the directory-wide lookup.
        let src = "fn helper() {}\nfn caller() {\n    helper();\n}\n";
        let call_byte = src.rfind("helper").unwrap();
        let (row, col) = row_col(src, call_byte);
        let got = resolve_local_at(&g, "demo.rs", src.as_bytes(), row, col).unwrap();
        assert!(got.is_none(), "a free/global name has no local binding, got {got:?}");
    }

    #[test]
    fn resolve_local_resolves_a_parameter() {
        let Some(g) = rust_with_locals() else { return };
        // Go-to-def on a use of a parameter resolves to the parameter binding.
        let src = "fn f(x: i32) -> i32 {\n    x + 1\n}\n";
        let use_byte = src.rfind('x').unwrap(); // the `x` in `x + 1`
        let (row, col) = row_col(src, use_byte);
        let got = resolve_local_at(&g, "demo.rs", src.as_bytes(), row, col)
            .unwrap()
            .expect("parameter should resolve");
        assert_eq!(got.name, "x");
        assert_eq!(got.line, 1, "parameter is declared on line 1");
    }

    #[test]
    fn resolve_local_returns_none_off_an_identifier() {
        let Some(g) = rust_with_locals() else { return };
        // Cursor on whitespace / punctuation is not an identifier — decline.
        let src = "fn f() {\n    let y = 1;\n}\n";
        let (row, col) = row_col(src, src.find('{').unwrap());
        let got = resolve_local_at(&g, "demo.rs", src.as_bytes(), row, col).unwrap();
        assert!(got.is_none());
    }

    /// A grammar *with* its `imports.scm`, or `None` when resolved from a root
    /// that ships none (e.g. a populated OS cache). The `GROVE_REGISTRY`-pinned
    /// integration suite covers this path unconditionally.
    fn lang_with_imports(lang: &str) -> Option<Grammar> {
        let g = registry::resolve(lang).ok()?;
        if g.imports_query.is_none() {
            eprintln!("skipping {lang}: no imports.scm (non-dev-stub root)");
            return None;
        }
        Some(g)
    }

    #[test]
    fn extract_imports_python_named_and_aliased() {
        let Some(g) = lang_with_imports("python") else { return };
        let src = b"from pkg.util import helper\nfrom pkg.mod import thing as t\n";
        let imps = extract_imports(&g, src).unwrap();
        assert!(
            imps.contains(&ImportBinding {
                name: "helper".into(),
                source: "helper".into(),
                module: "pkg.util".into(),
            }),
            "named import: {imps:?}"
        );
        assert!(
            imps.contains(&ImportBinding {
                name: "t".into(),
                source: "thing".into(),
                module: "pkg.mod".into(),
            }),
            "aliased import binds the alias, sources the original: {imps:?}"
        );
    }

    #[test]
    fn extract_imports_javascript_named_and_aliased() {
        let Some(g) = lang_with_imports("javascript") else { return };
        let src = b"import { compute } from \"./calc\";\nimport { compute as c } from \"./calc\";\n";
        let imps = extract_imports(&g, src).unwrap();
        assert!(
            imps.contains(&ImportBinding {
                name: "compute".into(),
                source: "compute".into(),
                module: "./calc".into(),
            }),
            "named import: {imps:?}"
        );
        assert!(
            imps.contains(&ImportBinding {
                name: "c".into(),
                source: "compute".into(),
                module: "./calc".into(),
            }),
            "aliased import: {imps:?}"
        );
    }

    #[test]
    fn supertype_pattern_detected_outside_strings() {
        // Crash-prone tree-sitter supertype syntax is flagged...
        assert!(has_supertype_pattern("(pattern/identifier) @local.definition"));
        assert!(has_supertype_pattern("(expression/variable) @local.reference"));
        // ...but ordinary queries and `/` inside predicate strings are not.
        assert!(!has_supertype_pattern("(identifier) @local.reference"));
        assert!(!has_supertype_pattern("((identifier) @x (#match? @x \"a/b\"))"));
        assert!(!has_supertype_pattern("(call function: (identifier) @name)"));
        // `/` inside a `;` comment is not supertype syntax (regression: nvim
        // locals.scm carry comments like "; if/else", "; try/catch").
        assert!(!has_supertype_pattern("; if/else\n(identifier) @local.reference"));
    }

    #[test]
    fn extract_imports_empty_without_query() {
        // Rust ships no imports.scm in the dev stub → no bindings, no error.
        let imps = extract_imports(&rust(), b"use foo::bar;\n").unwrap();
        assert!(imps.is_empty(), "rust has no imports query yet: {imps:?}");
    }

    #[test]
    fn extract_dedups_overlapping_matches() {
        // No symbol range appears twice with the same is_definition flag.
        let src = b"struct S;\nimpl S {\n    fn a(&self) {}\n    fn b(&self) {}\n}\n";
        let syms = extract(&rust(), "lib.rs", src).unwrap();
        let mut seen = std::collections::HashSet::new();
        for s in &syms {
            assert!(seen.insert((s.start_byte, s.end_byte, s.is_definition)), "duplicate: {s:?}");
        }
    }
}

fn name_matches(sym_name: &str, query_lc: &str, contains: bool) -> bool {
    let sym_lc = sym_name.to_lowercase();
    if contains {
        sym_lc.contains(query_lc)
    } else {
        sym_lc == query_lc
    }
}

/// `outline` — the definitions in one file, optionally filtered by kind.
pub fn outline(file: &Path, kind: Option<&str>) -> Result<Vec<Symbol>> {
    let grammar = registry::for_path(file)?;
    let src = read(file)?;
    let mut syms = engine::extract(&grammar, &rel(file), &src)?;
    syms.retain(|s| s.is_definition && kind.is_none_or(|k| kind_matches(&s.kind, k)));
    Ok(syms)
}

/// Project symbols to a JSON array at a detail level, to keep payloads bounded:
/// 0 = terse (kind/name/parent/line), 1 = default (adds id/col/signature, drops
/// byte offsets — the agent addresses symbols by id, not offset), 2 = full.
pub fn project(syms: &[Symbol], detail: u8) -> serde_json::Value {
    use serde_json::{Map, Value};
    if detail >= 2 {
        return serde_json::to_value(syms).unwrap_or(Value::Null);
    }
    let arr = syms
        .iter()
        .map(|s| {
            let mut m = Map::new();
            if detail >= 1 {
                m.insert("id".into(), s.id.clone().into());
            }
            m.insert("kind".into(), s.kind.clone().into());
            m.insert("name".into(), s.name.clone().into());
            if let Some(p) = &s.parent {
                m.insert("parent".into(), p.clone().into());
            }
            m.insert("line".into(), s.line.into());
            if detail >= 1 {
                m.insert("col".into(), s.col.into());
                m.insert("signature".into(), s.signature.clone().into());
            }
            Value::Object(m)
        })
        .collect();
    Value::Array(arr)
}

/// `symbols` — find across a directory, gitignore-aware.
pub fn symbols(
    dir: &Path,
    kind: Option<&str>,
    name: Option<&str>,
    refs: bool,
    name_contains: bool,
) -> Result<Vec<Symbol>> {
    let name_lc = name.map(str::to_lowercase);
    let mut all = Vec::new();
    for_each_source(dir, |grammar, relpath, src| {
        for s in engine::extract(grammar, relpath, src)? {
            if !refs && !s.is_definition {
                continue;
            }
            if kind.is_some_and(|k| !kind_matches(&s.kind, k)) {
                continue;
            }
            if name_lc
                .as_ref()
                .is_some_and(|n| !name_matches(&s.name, n, name_contains))
            {
                continue;
            }
            all.push(s);
        }
        Ok(())
    })?;
    Ok(all)
}

/// The result of `source`: the chosen symbol's code, plus any other
/// definitions that shared the name (so the agent can disambiguate).
#[derive(Debug, Serialize)]
pub struct SourceResult {
    pub id: String,
    pub source: String,
    #[serde(skip_serializing_if = "Vec::is_empty")]
    pub other_candidates: Vec<String>,
}

/// `source` — full code of a symbol, by id (`<lang>:<path>#<name>@<line>`) or
/// by file + name.
pub fn source(id_or_file: &str, name: Option<&str>) -> Result<SourceResult> {
    let (file, want, want_line): (PathBuf, String, Option<usize>) = match name {
        Some(n) => (PathBuf::from(id_or_file), n.to_string(), None),
        None => {
            let rest = id_or_file.split_once(':').map_or(id_or_file, |(_, r)| r);
            let (path, after) = rest
                .split_once('#')
                .context("symbol id must look like <lang>:<path>#<name>@<line>")?;
            // The `@<line>` suffix disambiguates duplicate-named definitions; keep
            // it so the requested symbol is the one returned.
            let (name, line) = match after.split_once('@') {
                Some((n, r)) => (n.to_string(), r.parse::<usize>().ok()),
                None => (after.to_string(), None),
            };
            (PathBuf::from(path), name, line)
        }
    };

    let grammar = registry::for_path(&file)?;
    let src = read(&file)?;
    let syms = engine::extract(&grammar, &rel(&file), &src)?;
    let matches: Vec<&Symbol> = syms
        .iter()
        .filter(|s| s.is_definition && s.name == want)
        .collect();

    // Prefer the exact-line match when the id carried a line; otherwise (name
    // mode, lineless id, or no line matched) fall back to the first definition.
    let chosen = match want_line.and_then(|r| matches.iter().find(|s| s.line == r)) {
        Some(c) => *c,
        None => match matches.first() {
            None => anyhow::bail!("no definition named `{want}` in {}", file.display()),
            Some(c) => *c,
        },
    };
    Ok(SourceResult {
        id: chosen.id.clone(),
        source: engine::slice(&src, chosen).to_string(),
        other_candidates: matches
            .iter()
            .filter(|s| s.id != chosen.id)
            .map(|s| s.id.clone())
            .collect(),
    })
}

/// `check` — ERROR / MISSING nodes in one file.
pub fn check(file: &Path) -> Result<Vec<Defect>> {
    let grammar = registry::for_path(file)?;
    let src = read(file)?;
    engine::check(&grammar, &src)
}

/// A site where a symbol is referenced (call site, type use, textual occurrence).
#[derive(Debug, Serialize)]
pub struct CallSite {
    pub file: String,
    /// 1-based line and column of the call (editor / `grep -n` convention).
    pub line: usize,
    pub col: usize,
    /// The function/method that contains this reference (`Type::method` when known).
    #[serde(skip_serializing_if = "Option::is_none")]
    pub in_function: Option<String>,
    /// The trimmed source text of the call's line.
    pub text: String,
    /// Provenance: `"structural"` for tree-sitter tag-resolved references,
    /// `"textual"` for whole-word grep matches that the tags query missed.
    /// Structural sites are high-precision (name-resolved); textual sites fill
    /// recall gaps (may include type annotations, imports, or comments).
    pub source: String,
}

/// `callers` — every reference to `name` across `dir`, with enclosing function.
///
/// Two passes are merged and deduped:
/// 1. **Structural** — tree-sitter tag-resolved references (all reference kinds:
///    call, type, implementation, etc.). High precision but low recall for names
///    that the tags query doesn't capture (e.g. class/type references in Java or
///    Python).
/// 2. **Textual** — whole-word grep for the name, for lines not already covered
///    by a structural hit. Higher recall but lower precision (may include type
///    annotations, imports, or comments). Each result carries a `source` field
///    (`"structural"` or `"textual"`) so the agent can prioritise.
///
/// Name-based: matches *any* symbol with this name (the slice does not resolve
/// receiver types). Honest over-match, documented for the agent.
pub fn callers(dir: &Path, name: &str) -> Result<Vec<CallSite>> {
    let mut out = Vec::new();
    for_each_source(dir, |grammar, relpath, src| {
        // Reuse the parse tree from extraction for the enclosing-function pass —
        // parsing dominates cost, so re-parsing here would double the work.
        let (syms, tree) = engine::extract_with_tree(grammar, relpath, src)?;
        let root = tree.root_node();

        // --- Structural pass: all non-definition tag-resolved references ---
        // The previous `is_call_kind` filter excluded type references, impl
        // references, etc., causing callers to return [] for heavily-used
        // class/type names (issue #33). Including all reference kinds fixes
        // that while the textual pass below fills the long tail.
        let structurals: Vec<&Symbol> = syms
            .iter()
            .filter(|s| !s.is_definition && s.name == name)
            .collect();
        // Lines covered by structural hits OR structural definitions of the same
        // name — the textual pass skips these to avoid duplicating references or
        // surfacing the definition line itself (callers is for references, not
        // definitions).
        let mut skip_lines: std::collections::HashSet<usize> =
            std::collections::HashSet::new();
        for s in &structurals {
            skip_lines.insert(s.line.saturating_sub(1));
        }
        for s in syms.iter().filter(|s| s.is_definition && s.name == name) {
            skip_lines.insert(s.line.saturating_sub(1));
        }
        for s in &structurals {
            out.push(CallSite {
                in_function: engine::enclosing_function_at(
                    root,
                    s.start_byte,
                    src,
                    &grammar.profile,
                ),
                file: s.file.clone(),
                line: s.line,
                col: s.col,
                text: s.signature.clone(),
                source: "structural".to_string(),
            });
        }

        // --- Textual pass: whole-word grep for the name ---
        // Covers references that the tags query misses (type annotations, imports,
        // dynamic dispatch, etc.). Only adds lines not already covered by structural
        // hits or definitions, so there's no duplication.
        let src_str = std::str::from_utf8(src).unwrap_or("");
        for (row, line_text) in src_str.lines().enumerate() {
            if skip_lines.contains(&row) {
                continue; // already covered by a structural hit or definition
            }
            if !has_whole_word(line_text, name) {
                continue;
            }
            // Find the byte offset of the first occurrence for enclosing-function.
            let col = line_text.find(name).unwrap_or(0);
            let byte = line_offset(src, row) + col;
            out.push(CallSite {
                in_function: engine::enclosing_function_at(root, byte, src, &grammar.profile),
                file: relpath.to_string(),
                line: row + 1,
                col: col + 1,
                text: line_text.trim().to_string(),
                source: "textual".to_string(),
            });
        }

        Ok(())
    })?;
    Ok(out)
}

/// Byte offset of the start of line `row` (0-based) in `source`.
fn line_offset(source: &[u8], row: usize) -> usize {
    let mut off = 0;
    for _ in 0..row {
        match source[off..].iter().position(|&b| b == b'\n') {
            Some(pos) => off += pos + 1,
            None => return source.len(),
        }
    }
    off
}

/// Does `haystack` contain `needle` as a whole word?
/// A word boundary is the start/end of `haystack` or a char that is not
/// ASCII alphanumeric or underscore. This mirrors how `grep -w` works for
/// identifier names, without requiring a regex dependency.
fn has_whole_word(haystack: &str, needle: &str) -> bool {
    let needle_bytes = needle.as_bytes();
    let haystack_bytes = haystack.as_bytes();
    if needle_bytes.is_empty() {
        return false;
    }
    let mut i = 0;
    while i + needle_bytes.len() <= haystack_bytes.len() {
        if &haystack_bytes[i..i + needle_bytes.len()] == needle_bytes {
            let before_ok = i == 0 || !is_ident_char(haystack_bytes[i - 1]);
            let after_ok =
                i + needle_bytes.len() == haystack_bytes.len()
                    || !is_ident_char(haystack_bytes[i + needle_bytes.len()]);
            if before_ok && after_ok {
                return true;
            }
        }
        // Advance: skip ahead past the current byte (handles multi-byte UTF-8
        // correctly because we only match on ASCII needle/ident chars).
        i += 1;
    }
    false
}

fn is_ident_char(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

/// Parse a `file:line:col` position string. `line`/`col` are 1-based on input
/// (the editor / `grep -n` convention grove prints), and are returned as the
/// 0-based row/col tree-sitter expects, so the location grove prints round-trips
/// straight back into `--at`.
pub fn parse_pos(s: &str) -> Result<(PathBuf, usize, usize)> {
    let parts: Vec<&str> = s.rsplitn(3, ':').collect();
    match parts.as_slice() {
        [col, line, file] => {
            let line: usize = line.parse().map_err(|_| anyhow::anyhow!("bad line in `{s}`"))?;
            let col: usize = col.parse().map_err(|_| anyhow::anyhow!("bad col in `{s}`"))?;
            Ok((
                PathBuf::from(file),
                line.saturating_sub(1),
                col.saturating_sub(1),
            ))
        }
        _ => anyhow::bail!("expected file:line:col, got `{s}`"),
    }
}

/// A definition in a `map` result, with its outgoing references.
#[derive(Debug, Serialize)]
pub struct MapEntry {
    pub id: String,
    pub kind: String,
    pub name: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub parent: Option<String>,
    pub row: usize,
    pub signature: String,
    /// Names of other symbols this definition references (outgoing edges).
    #[serde(skip_serializing_if = "Vec::is_empty")]
    pub references: Vec<String>,
}

/// A file in a `map` result, with its definitions and their references.
#[derive(Debug, Serialize)]
pub struct FileMap {
    pub file: String,
    pub entries: Vec<MapEntry>,
}

/// `map` — compact structural map of a directory: every definition grouped by
/// file, with each definition's outgoing references (which other symbols it
/// calls or uses). No source bodies — just the dependency graph. Use this
/// instead of many `symbols`+`source` calls when you need a broad picture of
/// how code connects.
pub fn map(
    dir: &Path,
    kind: Option<&str>,
    name: Option<&str>,
    name_contains: bool,
) -> Result<Vec<FileMap>> {
    let name_lc = name.map(str::to_lowercase);
    let mut file_maps = Vec::new();
    for_each_source(dir, |grammar, relpath, src| {
        let syms = engine::extract(grammar, relpath, src)?;

        // Collect matching definition indices, sorted by byte-range size
        // ascending so innermost (narrowest) definitions come first. This
        // lets us attribute each reference to its innermost enclosing def.
        let mut defs: Vec<usize> = syms
            .iter()
            .enumerate()
            .filter(|(_, s)| s.is_definition)
            .filter(|(_, s)| kind.is_none_or(|k| kind_matches(&s.kind, k)))
            .filter(|(_, s)| name_lc.as_ref().is_none_or(|n| name_matches(&s.name, n, name_contains)))
            .map(|(i, _)| i)
            .collect();
        defs.sort_by_key(|&i| syms[i].end_byte - syms[i].start_byte);

        // Attribute each reference to the innermost containing definition.
        let mut ref_map: std::collections::HashMap<usize, Vec<String>> =
            std::collections::HashMap::new();
        for (_, s) in syms.iter().enumerate() {
            if s.is_definition {
                continue;
            }
            for &d in &defs {
                if s.start_byte >= syms[d].start_byte && s.end_byte <= syms[d].end_byte {
                    ref_map.entry(d).or_default().push(s.name.clone());
                    break; // first (narrowest) match wins
                }
            }
        }

        // Deduplicate reference names per definition.
        for names in ref_map.values_mut() {
            names.sort();
            names.dedup();
        }

        // Build entries, sorted by row for deterministic output.
        let mut entries: Vec<MapEntry> = defs
            .iter()
            .map(|&d| {
                let s = &syms[d];
                let mut refs = ref_map.remove(&d).unwrap_or_default();
                // Remove self-references (e.g. recursive calls).
                refs.retain(|n| n != &s.name);
                MapEntry {
                    id: s.id.clone(),
                    kind: s.kind.clone(),
                    name: s.name.clone(),
                    parent: s.parent.clone(),
                    row: s.line,
                    signature: s.signature.clone(),
                    references: refs,
                }
            })
            .collect();
        entries.sort_by_key(|e| e.row);

        if !entries.is_empty() {
            file_maps.push(FileMap {
                file: relpath.to_string(),
                entries,
            });
        }
        Ok(())
    })?;
    file_maps.sort_by(|a, b| a.file.cmp(&b.file));
    Ok(file_maps)
}

/// `definition` — exact-name definitions of `name` across `dir` (go-to-def).
pub fn definition(dir: &Path, name: &str) -> Result<Vec<Symbol>> {
    // `name_contains = false`: `definition` is exact by contract, so pre-filter
    // exactly — cheaper than pulling every substring hit then retaining.
    let mut defs = symbols(dir, None, Some(name), false, false)?;
    defs.retain(|s| s.name == name);
    Ok(defs)
}

/// `definition --at` — resolve the identifier at a usage site, then find its
/// definition(s). `row`/`col` are 0-based tree-sitter coords (callers feed the
/// output of [`parse_pos`], which converts the 1-based `file:line:col` users
/// type). Returns the resolved name alongside the matches.
pub fn definition_at(file: &Path, row: usize, col: usize, dir: &Path) -> Result<(String, Vec<Symbol>)> {
    let grammar = registry::for_path(file)?;
    let src = read(file)?;
    let name = engine::with_tree(&grammar, &src, |root, profile| {
        engine::identifier_at(root, row, col, &src, profile)
    })?
    .with_context(|| format!("no identifier at {}:{row}:{col}", file.display()))?;
    // Scope-aware first (ADR 0001 Step 1): if the cursor's identifier binds to a
    // local definition in an enclosing scope, that single binding *is* the
    // answer — a shadowing local must win over a same-named global. Only when
    // there is no local binding do we fall back to the directory-wide name
    // lookup (the historical behavior, also the floor for free/global names).
    if let Some(local) = engine::resolve_local_at(&grammar, &rel(file), &src, row, col)? {
        return Ok((name, vec![local]));
    }
    // Import-edge next (ADR 0001 Step 2): if the name is brought in by an import,
    // resolve it to the definition in the target file — cross-file go-to-def
    // without an index. Falls through to directory-wide lookup on any miss.
    let imported = resolve_import_at(file, &name, dir, &grammar, &src)?;
    if !imported.is_empty() {
        return Ok((name, imported));
    }
    let defs = definition(dir, &name)?;
    Ok((name, defs))
}

/// Resolve `name` to a definition in the file an import binds it from. Returns an
/// empty vec when the language has no import-resolution strategy, `name` isn't
/// imported here, the module doesn't resolve to a file on disk, or that file has
/// no matching top-level definition — every case the caller treats as "fall back
/// to directory-wide lookup". Parses at most one extra file (the target), so the
/// whole operation stays stateless and bounded by import depth, not repo size.
fn resolve_import_at(
    file: &Path,
    name: &str,
    dir: &Path,
    grammar: &Grammar,
    src: &[u8],
) -> Result<Vec<Symbol>> {
    let Some(strategy) = grammar.profile.import_resolution.as_deref() else {
        return Ok(Vec::new());
    };
    let Some(binding) = engine::extract_imports(grammar, src)?
        .into_iter()
        .find(|b| b.name == name)
    else {
        return Ok(Vec::new());
    };
    for cand in import_candidate_paths(strategy, &binding.module, file, dir) {
        if !cand.is_file() {
            continue;
        }
        let tsrc = read(&cand)?;
        let trel = rel(&cand);
        let defs: Vec<Symbol> = engine::extract(grammar, &trel, &tsrc)?
            .into_iter()
            .filter(|s| s.is_definition && s.name == binding.source)
            .collect();
        if !defs.is_empty() {
            return Ok(defs);
        }
    }
    Ok(Vec::new())
}

/// Candidate file paths a module path could resolve to, by strategy. The first
/// that exists and contains the imported definition wins. Pure path arithmetic —
/// no IO here.
fn import_candidate_paths(
    strategy: &str,
    module: &str,
    current_file: &Path,
    dir: &Path,
) -> Vec<PathBuf> {
    match strategy {
        // Python: `foo.bar` → `<root>/foo/bar.py` | `<root>/foo/bar/__init__.py`.
        // Leading dots are relative to the current file's package: one dot = the
        // file's own directory, each extra dot climbs one more.
        "dotted_package" => {
            let dots = module.chars().take_while(|&c| c == '.').count();
            let rest = &module[dots..];
            let parts: Vec<&str> = rest.split('.').filter(|p| !p.is_empty()).collect();
            let mut base = if dots == 0 {
                dir.to_path_buf()
            } else {
                let mut b = current_file.parent().unwrap_or(dir).to_path_buf();
                for _ in 0..dots.saturating_sub(1) {
                    b = b.parent().map(Path::to_path_buf).unwrap_or(b);
                }
                b
            };
            for p in &parts {
                base.push(p);
            }
            vec![base.with_extension("py"), base.join("__init__.py")]
        }
        // JS/TS: only relative specifiers resolve to a file; bare specifiers
        // (`react`) are package imports we don't chase. `./util` → `./util.js` |
        // `./util.jsx` | `./util/index.js`.
        "relative_path" => {
            if !module.starts_with('.') {
                return Vec::new();
            }
            let joined = normalize(&current_file.parent().unwrap_or(dir).join(module));
            if joined.extension().is_some() {
                return vec![joined];
            }
            vec![
                joined.with_extension("js"),
                joined.with_extension("jsx"),
                joined.join("index.js"),
            ]
        }
        _ => Vec::new(),
    }
}

/// Lexically normalize a path, resolving `.` and `..` without touching the disk
/// (so `a/b/../util` → `a/util`). Symlink-blind, which is fine for module paths.
fn normalize(path: &Path) -> PathBuf {
    use std::path::Component;
    let mut out = PathBuf::new();
    for comp in path.components() {
        match comp {
            Component::CurDir => {}
            Component::ParentDir => {
                out.pop();
            }
            other => out.push(other.as_os_str()),
        }
    }
    out
}

